import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface LearningProgress {
  wordsLearned: number;
  dailyGoal: number;
  wordsToday: number;
  streakDays: number;
}

interface RecentWord {
  word: string;
  definition: string;
}

interface GoalProgress {
  day: string;
  words: number;
}

interface VocabData {
  learningProgress: LearningProgress;
  recentWords: RecentWord[];
  goalProgress: GoalProgress[];
}

export default function Widget() {
  const vocabData = response.data as VocabData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#F5F5F5' }}>
              Lexicon Pro - Vocabulary Builder
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mb: 1 }}>
              Version 1.0
            </Typography>
            <Typography variant="body2" sx={{ color: '#F5F5F5' }}>
              Words Learned: {vocabData.learningProgress.wordsLearned}
            </Typography>
            <Typography variant="body2" sx={{ color: '#F5F5F5' }}>
              Daily Goal: {vocabData.learningProgress.dailyGoal}
            </Typography>
            <Typography variant="body2" sx={{ color: '#F5F5F5' }}>
              Words Today: {vocabData.learningProgress.wordsToday}
            </Typography>
            <Typography variant="body2" sx={{ color: '#F5F5F5' }}>
              Streak Days: {vocabData.learningProgress.streakDays}
            </Typography>
          </Box>

          <Box>
            <Typography variant="subtitle1" sx={{ color: '#F5F5F5', mb: 1 }}>
              Recent Words
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {vocabData.recentWords.map((word, index) => (
                <Chip
                  key={index}
                  label={word.word}
                  sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#37474F', color: '#F5F5F5' }}
                />
              ))}
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: vocabData.goalProgress.map(g => g.words),
                  color: '#50E3C2',
                  label: 'Words',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: vocabData.goalProgress.map(g => g.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'words' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="words"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
